@RestController
public class LoginController {

    private final AuthenticationManager authenticationManager;
    private final OpenIDClientRegistrationRepository clientRegistrations;

    @Autowired
    public LoginController(AuthenticationManager authenticationManager, OpenIDClientRegistrationRepository clientRegistrations) {
        this.authenticationManager = authenticationManager;
        this.clientRegistrations = clientRegistrations;
    }

    @GetMapping("/login")
    public String login() throws Exception {
        ClientRegistration clientRegistration = clientRegistrations.findByRegistrationId("client-id");

        var authorizationRequest = new AuthorizationRequest(clientRegistration.getAuthorizationUrl());
        authorizationRequest.setRedirectUri("http://localhost:8080/login");
        authorizationRequest.setResponseType(Arrays.asList("id_token"));
        Map<String, String> parameters = authorizationRequest.getRequestParameters();

        parameters.put("response_mode", "query");
        parameters.put("scope", Arrays.asList(
                AuthorizationScope.OPENID,
                AuthorizationScope.PROFILE
        ));

        var authorizationUrl = clientRegistration.getAuthorizationUrl(parameters);

        return "Go to the following URL: " + authorizationUrl;
    }
}

@RestController
public class TokenController {

    private final ClientRegistration clientRegistration;

    @Autowired
    public TokenController(ClientRegistration clientRegistration) {
        this.clientRegistration = clientRegistration;
    }

    @GetMapping("/token")
    public String token() throws Exception {
        ClientRegistration clientRegistration = new InMemoryClientRegistrations().get("client-id");

        var tokenRequest = new AuthorizationGrantTokenRequest(
                "authorization_code",
                "12345",
                "http://localhost:8080/login"
        );

        var tokenResponse = clientRegistration.getTokenEndpoint().token(tokenRequest);
        return tokenResponse.getAccessToken();
    }
}

@RestController
public class UserinfoController {

    @GetMapping("/userinfo")
    public String userinfo() throws Exception {
        ClientRegistration clientRegistration = new InMemoryClientRegistrations().get("client-id");

        String token = TokenController.token();

        var authorizationRequest = new AuthorizationRequest(clientRegistration.getUserInfoUrl());
        Map<String, String> parameters = authorizationRequest.getRequestParameters();
        parameters.put("access_token", token);

        var userinfoResponse = clientRegistration.getUserInfoEndpoint().userInfo(parameters);
        return userinfoResponse.getIdToken().getClaim("name");
    }
}